mapper.update:
UPDATE transaction_category
SET name = #{category.name},
type = #{category.type},
code = #{category.code},
is_default = #{category.isDefault}
WHERE id = #{id} AND user_id = #{userId}

mapper.select:
SELECT id,
user_id AS userId,
name,
type,
code,
is_default AS isDefault
FROM transaction_category
WHERE user_id = #{userId}
AND name = #{name}
AND type = #{type}
